+            let mut arena = VersionArena::new();
+            let mut indices = Vec::new();
+
+            for i in 0..alloc_count {
+                // alloc_count is bounded to 200, so truncation cannot occur.
+                let pgno = PageNumber::new(u32::try_from(i).unwrap().max(1)).unwrap();
+                let v = PageVersion {
+                    pgno,
